import pytest
from hydro.stage_cost_function import ProxyStageCostFunction
from hydro.bellman import BellmanValuesProxy
from hydro.trajectories import OptimalTrajectories
from tqdm import tqdm
import numpy as np

dir_study = "test_data/two_nodes"
area1="area1"
pbar = tqdm(total=0, disable=True)
proxy = ProxyStageCostFunction(dir_study=dir_study,
              name_area=area1,
              MC_years=10,
              alpha=2,
              pbar=pbar)

bellman_values = BellmanValuesProxy(proxy=proxy,
                                    PENALTY_FACTOR=0.4,
                                    pbar=pbar)


def test_bellman_value()->None:
    assert bellman_values.mean_bv.shape == (52,51)
    expected_final_bellman_value = np.array([1964728703439.4146, 1908593597626.8599, 1852458491814.3054, 1796323386001.7505, 1740188280189.1956, 1684053174376.641, 1627918068564.0862, 1571782962751.5317, 1515647856938.9768, 1459512751126.4224, 1403377645313.8674, 1347242539501.313, 1291107433688.758, 1234972327876.2036, 1178837222063.649, 1122702116251.0942, 1066567010438.5394, 1010431904625.9846, 954296798813.4299, 898161693000.8752, 842026587188.3206, 785891481375.7659, 729756375563.2112, 673621269750.6565, 617486163938.1018, 561351058125.5471, 505215952312.9923, 449080846500.4376, 392945740687.8827, 336810634875.32825, 280675529062.77356, 224540423250.2188, 168405317437.66412, 112270211625.1094, 56135105812.55444, 0.0, 56135105812.5547, 112270211625.1094, 168405317437.66412, 224540423250.2188, 280675529062.77356, 336810634875.328, 392945740687.88293, 449080846500.4376, 505215952312.9923, 561351058125.5471, 617486163938.1018, 673621269750.6565, 729756375563.2112, 785891481375.7659, 842026587188.3206])
    
    expected_intial_bellman_value = np.array([8675867568507.178, 8648790912895.88, 8622405556019.008, 8596682266941.396, 8571621024627.51, 8547176156346.435, 8523335575438.081, 8500061223831.192, 8477355197376.709, 8455192464915.682, 8433572045804.966, 8412490999275.256, 8391941714799.471, 8371914325581.361, 8352425059057.067, 8333420442746.43, 8314944595162.073, 8296976826926.377, 8279483280364.549, 8262500852908.756, 8245954169209.453, 8229866845569.755, 8214222819725.236, 8198988245102.201, 8184180174366.992, 8169756379133.362, 8155693027055.701, 8142039292284.541, 8128724068306.576, 8115748653803.9375, 8103139031424.386, 8090903304853.875, 8078996684066.214, 8067456054422.25, 8056284973446.666, 8045457570115.686, 8035010589783.516, 8024941396951.014, 8015249766888.67, 8005938747996.799, 7996988186382.873, 7988438906069.448, 7980316657888.564, 7972591935414.885, 7965281424398.779, 7958436466600.166, 7951986272530.932, 7946005160503.599, 7940491426008.106, 7935410135117.291, 7930825931615.814]
    )
    assert bellman_values.mean_bv[51,:] == pytest.approx(expected_final_bellman_value)
    assert bellman_values.mean_bv[0,:] == pytest.approx(expected_intial_bellman_value)
    assert bellman_values.mean_bv[50,33] == pytest.approx(93807313270.1012)

trajectories = OptimalTrajectories(bellman_values=bellman_values,
                                   pbar=pbar)

